            .componentOrder(Comparator.comparing(component -> {
                if (component instanceof Shape) {
                    Shape shape = (Shape) component;
                    return shape.getId().getName().equals("Table") ? "z" : shape.getId().getName();
                }
                return component.toShapeId().toString();
            }))
            .build()
            .serialize(model);

