    @Test
    public void supportsCustomComponentOrderComparator() {
        String stringModel = "$version: \"2.0\"\n"
                + "namespace smithy.example\n"
                + "metadata beta = \"beta\"\n"
                + "metadata alpha = \"alpha\"\n"
                + "@readonly\n"
                + "@documentation(\"docs\")\n"
                + "string First\n"
                + "structure Table {}\n"
                + "string Column\n";
        Model model = Model.assembler().addUnparsedModel("test.smithy", stringModel).assemble().unwrap();
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .componentOrder(Comparator.comparing(component -> {
                    if (component instanceof Shape) {
                        Shape shape = (Shape) component;
                        return shape.getId().getName().equals("Table") ? "z" : shape.getId().getName();
                    }
                    return component.toShapeId().toString();
                }))
                .build()
                .serialize(model);

        String modelResult = reserialized.get(Paths.get("smithy.example.smithy")).replace("\r\n", "\n");
        String metadataResult = reserialized.get(Paths.get("metadata.smithy")).replace("\r\n", "\n");

        assertThat(modelResult.indexOf("string Column"), is(not(-1)));
        assertThat(modelResult.indexOf("structure Table"), is(not(-1)));
        assertThat(modelResult.indexOf("string Column") < modelResult.indexOf("structure Table"), is(true));
        assertThat(modelResult.indexOf("@documentation"), is(not(-1)));
        assertThat(modelResult.indexOf("@tags"), is(not(-1)));
        assertThat(modelResult.indexOf("@documentation") < modelResult.indexOf("@tags"), is(true));
        assertThat(metadataResult.indexOf("metadata alpha"), is(not(-1)));
        assertThat(metadataResult.indexOf("metadata beta"), is(not(-1)));
        assertThat(metadataResult.indexOf("metadata alpha") < metadataResult.indexOf("metadata beta"), is(true));
    }

